  "handoff_brief": {
    "recipient": "Shaq",
    "task_context": "Implement an Order State Management feature within the Order Fulfillment bounded context. The feature centers on a PATCH endpoint for order state transitions, enforced by a state machine that encodes domain invariants, plus a RefundService that depends on verified order state before issuing refunds.",
    "domain_rules": [
      {
        "rule": "An order cannot transition from SHIPPED to PENDING",
        "testable_assertion": "Calling OrderStateMachine.transition(SHIPPED, PENDING) throws/returns ORDER_STATE_INVALID"
      },
      {
        "rule": "A refund can only be issued on a DELIVERED order",
        "testable_assertion": "RefundService.issueRefund(orderId) fails with a domain error when the order state is anything other than DELIVERED"
      }
    ],
    "architecture_guidance": [
      {
        "decision": "Expose a PATCH /orders/{id}/state endpoint for all state transitions",
        "implementation_note": "The endpoint accepts the target state in the request body. All transition validation is delegated to OrderStateMachine — the controller/handler should not contain transition logic."
      },
      {
        "decision": "State transitions validated in an OrderStateMachine class",
        "implementation_note": "OrderStateMachine owns the full map of legal transitions. It should be a pure domain object with no infrastructure dependencies, making it trivially unit-testable."
      },
      {
        "decision": "Refund logic lives in a separate RefundService that verifies order state before issuing",
        "implementation_note": "RefundService calls the order service (or queries order state directly) to confirm the order is in DELIVERED state before proceeding. This is a cross-domain check — keep the coupling to a single state-verification call, not a deep dependency on order internals."
      }
    ],
    "acceptance_criteria": [
      {
        "criterion": "Reject invalid SHIPPED-to-PENDING transition",
        "given": "An order in SHIPPED state",
        "when": "A PATCH /orders/{id}/state request attempts to set state to PENDING",
        "then": "The request is rejected with error code ORDER_STATE_INVALID and an appropriate HTTP 422 response"
      },
      {
        "criterion": "Reject refund on non-DELIVERED order",
        "given": "An order in any state other than DELIVERED",
        "when": "RefundService.issueRefund is called for that order",
        "then": "The refund is rejected with a domain error indicating the order must be in DELIVERED state"
      },
      {
        "criterion": "Allow refund on DELIVERED order",
        "given": "An order in DELIVERED state",
        "when": "RefundService.issueRefund is called for that order",
        "then": "The refund proceeds successfully"
      }
    ],
    "terminology_alignment": [
      {
        "domain_term": "State invariant",
        "technical_term": "Transition guard / validation rule",
        "definition": "A business rule that forbids certain state transitions. Encoded as guard conditions in OrderStateMachine that reject illegal transitions before they are applied."
      },
      {
        "domain_term": "ORDER_STATE_INVALID",
        "technical_term": "Domain error code",
        "definition": "The canonical error code returned when a requested state transition violates a domain invariant. Should appear in both the domain exception and the API error response body."
      }
    ],
    "contradictions_resolved": [],
    "open_questions": []
  },
  "escalations": [],
  "confidence": {
    "level": 92,
    "high_confidence_areas": [
      "Domain invariants are clear and directly testable",
      "Architecture boundaries between OrderStateMachine and RefundService are well-defined",
      "Acceptance criteria map 1:1 to stated domain rules"
    ],
    "low_confidence_areas": [
      "Full set of legal state transitions not specified — only one illegal transition (SHIPPED→PENDING) was called out; Shaq may need to clarify or request the complete transition map",
      "HTTP status code for rejection not explicitly stated by either agent — 422 assumed as conventional choice"
    ],
    "assumptions": [
      "OrderStateMachine is a pure domain object, not an infrastructure-aware service",
      "RefundService verifies state via a lightweight query, not by attempting the transition itself",
      "The PATCH endpoint returns 422 Unprocessable Entity for domain-invalid transitions"
    ]
  }
}

